import React from 'react';

export const legalContent = {
  privacyPolicy: {
    title: "Política de Privacidade",
    lastUpdated: "3 de Outubro de 2025",
    sections: [
      {
        title: "1. Quais Dados Coletamos?",
        content: <><p>Coletamos informações que você nos fornece diretamente...</p> {/* ...e o resto do conteúdo da privacidade... */}</>
      },
      // ... todas as outras seções da política de privacidade aqui ...
      {
        title: "5. Fale Conosco",
        content: <p>Se tiver qualquer dúvida sobre esta política..., entre em contato: <a href="mailto:contato@cortexstudio.com.br">contato@cortexstudio.com.br</a></p>
      }
    ]
  },
  termsOfUse: {
    title: "Termos de Uso",
    lastUpdated: "3 de Outubro de 2025",
    // Adicionamos um ID aqui para podermos criar um link direto
    anchorId: "termos-de-uso", 
    sections: [
      {
        title: "1. Aceitação dos Termos",
        content: <p>Bem-vindo à <strong>Cortex Studio</strong>. Ao acessar e utilizar nosso website...</p>
      },
      // ... todas as outras seções dos termos de uso aqui ...
      {
        title: "9. Contato",
        content: <p>Para qualquer dúvida relacionada a estes termos, entre em contato: <a href="mailto:contato@cortexstudio.com.br">contato@cortexstudio.com.br</a>.</p>
      }
    ]
  }
};
